/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  // Handle negative or zero bits - treat as invalid, use 0 buckets
  if (n_bits_ <= 0) {
    n_bits_ = 0;
    num_buckets_ = 0;
  } else {
    num_buckets_ = static_cast<size_t>(1) << n_bits_;
  }
  registers_.resize(num_buckets_, 0);
}

/**
 * @brief Function that computes binary.
 *
 * @param[in] hash
 * @returns binary of a given hash
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

/**
 * @brief Function that computes leading zeros.
 *
 * @param[in] bset - binary values of a given bitset
 * @returns leading zeros of given binary set
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost 1 bit (counting from LSB starting at 1)
  // We scan from the MSB (position BITSET_CAPACITY-1) down to position 0
  for (int i = BITSET_CAPACITY - 1; i >= 0; i--) {
    if (bset.test(i)) {
      // Position counting from right (LSB=1), so position is i+1
      return static_cast<uint64_t>(i + 1);
    }
  }
  // If all zeros, return BITSET_CAPACITY (max position)
  return BITSET_CAPACITY;
}

/**
 * @brief Adds a value into the HyperLogLog.
 *
 * @param[in] val - value that's added into hyperloglog
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (num_buckets_ == 0) {
    return;
  }

  hash_t hash = CalculateHash(val);
  std::bitset<BITSET_CAPACITY> binary = ComputeBinary(hash);

  // Extract the bucket index from the first n_bits_ bits (MSB)
  // The bucket index is taken from the most significant n_bits_ bits
  uint64_t bucket_idx = 0;
  for (int i = 0; i < n_bits_; i++) {
    if (binary.test(BITSET_CAPACITY - 1 - i)) {
      bucket_idx |= (static_cast<uint64_t>(1) << (n_bits_ - 1 - i));
    }
  }

  // Create a mask to get the remaining bits (excluding the bucket index bits)
  // We need to find the position of the leftmost 1 in the remaining bits
  std::bitset<BITSET_CAPACITY> remaining_bits;
  for (int i = 0; i < BITSET_CAPACITY - n_bits_; i++) {
    remaining_bits[i] = binary[i];
  }

  // Find position of leftmost 1 in the remaining bits
  uint64_t position = 0;
  for (int i = BITSET_CAPACITY - n_bits_ - 1; i >= 0; i--) {
    if (remaining_bits.test(i)) {
      position = static_cast<uint64_t>(BITSET_CAPACITY - n_bits_ - i);
      break;
    }
  }
  if (position == 0) {
    position = BITSET_CAPACITY - n_bits_ + 1;
  }

  // Update the register with max value (thread-safe)
  std::lock_guard<std::mutex> lock(mutex_);
  if (position > registers_[bucket_idx]) {
    registers_[bucket_idx] = position;
  }
}

/**
 * @brief Function that computes cardinality.
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (num_buckets_ == 0) {
    cardinality_ = 0;
    return;
  }

  // Calculate harmonic mean of 2^(-register[i])
  double sum = 0.0;
  for (size_t i = 0; i < num_buckets_; i++) {
    sum += std::pow(2.0, -static_cast<double>(registers_[i]));
  }

  // HyperLogLog formula: E = alpha * m^2 / sum(2^(-M[j]))
  // where alpha = 0.79402 (CONSTANT), m = num_buckets_
  double m = static_cast<double>(num_buckets_);
  double estimate = CONSTANT * m * m / sum;

  cardinality_ = static_cast<size_t>(estimate);
