//===----------------------------------------------------------------------===//
//
//                         BusTub
//
// hyperloglog_presto.cpp
//
// Identification: src/primer/hyperloglog_presto.cpp
//
// Copyright (c) 2015-2025, Carnegie Mellon University Database Group
//
//===----------------------------------------------------------------------===//

#include "primer/hyperloglog_presto.h"
#include <cmath>

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits)
    : cardinality_(0), n_leading_bits_(n_leading_bits) {
  // Handle negative bits - treat as invalid, use 0 buckets
  if (n_leading_bits_ < 0) {
    n_leading_bits_ = 0;
    num_buckets_ = 0;
  } else {
    num_buckets_ = static_cast<size_t>(1) << n_leading_bits_;
  }
  dense_bucket_.resize(num_buckets_, std::bitset<DENSE_BUCKET_SIZE>(0));
}

/** @brief Element is added for HLL calculation. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (num_buckets_ == 0) {
    return;
  }

  hash_t hash = CalculateHash(val);

  // For Presto HLL, we use the hash directly (64 bits)
  // Extract bucket index from the leading n_leading_bits_ bits (MSB)
  uint64_t bucket_idx = 0;
  if (n_leading_bits_ > 0) {
    bucket_idx = hash >> (64 - n_leading_bits_);
  }

  // Count leading zeros in the remaining bits + 1 (position of leftmost 1)
  // The remaining bits start after the bucket index bits
  // Create mask to clear the bucket index bits
  uint64_t remaining_bits = hash;
  if (n_leading_bits_ > 0 && n_leading_bits_ < 64) {
    // Clear the top n_leading_bits_ bits
    remaining_bits = hash << n_leading_bits_;
  } else if (n_leading_bits_ >= 64) {
    remaining_bits = 0;
  }

  // Count leading zeros and add 1 for the position
  uint64_t position = 1;
  if (remaining_bits == 0) {
    // All zeros - maximum position
    position = 64 - n_leading_bits_ + 1;
  } else {
    // Count leading zeros in remaining_bits
    // __builtin_clzll counts leading zeros for 64-bit
    int leading_zeros = __builtin_clzll(remaining_bits);
    position = static_cast<uint64_t>(leading_zeros + 1);
  }

  // The dense bucket stores lower 4 bits, overflow stores upper 3 bits
  // Total value is: (overflow << 4) | dense
  // Max value storable: (7 << 4) | 15 = 127

  // Get current value
  uint64_t current_dense = dense_bucket_[bucket_idx].to_ullong();
  uint64_t current_overflow = 0;
  if (overflow_bucket_.find(static_cast<uint16_t>(bucket_idx)) != overflow_bucket_.end()) {
    current_overflow = overflow_bucket_[static_cast<uint16_t>(bucket_idx)].to_ullong();
  }
  uint64_t current_value = (current_overflow << DENSE_BUCKET_SIZE) | current_dense;

  // Only update if new position is greater
  if (position > current_value) {
    // Split position into dense (lower 4 bits) and overflow (upper bits)
    uint64_t new_dense = position & 0xF;                                     // Lower 4 bits
    uint64_t new_overflow = (position >> DENSE_BUCKET_SIZE) & 0x7;           // Next 3 bits

    dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(new_dense);
    overflow_bucket_[static_cast<uint16_t>(bucket_idx)] = std::bitset<OVERFLOW_BUCKET_SIZE>(new_overflow);
  }
}

/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (num_buckets_ == 0) {
    cardinality_ = 0;
    return;
  }

  // Calculate harmonic mean of 2^(-register[i])
  double sum = 0.0;
  for (size_t i = 0; i < num_buckets_; i++) {
    // Reconstruct the full value from dense and overflow buckets
    uint64_t dense_val = dense_bucket_[i].to_ullong();
    uint64_t overflow_val = 0;
    if (overflow_bucket_.find(static_cast<uint16_t>(i)) != overflow_bucket_.end()) {
      overflow_val = overflow_bucket_[static_cast<uint16_t>(i)].to_ullong();
    }
    uint64_t register_val = (overflow_val << DENSE_BUCKET_SIZE) | dense_val;
    sum += std::pow(2.0, -static_cast<double>(register_val));
  }

  // HyperLogLog formula: E = alpha * m^2 / sum(2^(-M[j]))
  double m = static_cast<double>(num_buckets_);
  double estimate = CONSTANT * m * m / sum;

  cardinality_ = static_cast<uint64_t>(estimate);
}

template class HyperLogLogPresto<int64_t>;
template class HyperLogLogPresto<std::string>;
}  // namespace bustub

